import { test, expect } from '../../support/fixtures/csrfCookiePolicy.fixture';

test.describe('Story 0.4 automate - csrf and parent-domain cookie enforcement journey', () => {
  test.skip('blocks cross-subdomain state-changing fetch when csrf header is missing @P0', async ({
    page,
    csrfGuardRequestWithoutToken,
  }) => {
    // Given browser context is authenticated but missing CSRF header proof
    await page.goto('/');

    // When app surface performs a state-changing request to the API surface
    const result = await page.evaluate(
      async ({ headers, payload }) => {
        const response = await fetch('/api/v1/platform/_kernel/security/csrf/guard', {
          method: 'POST',
          credentials: 'include',
          headers: {
            'content-type': 'application/json',
            ...headers,
          },
          body: JSON.stringify(payload),
        });

        return {
          status: response.status,
          body: await response.json(),
        };
      },
      {
        headers: csrfGuardRequestWithoutToken.headers,
        payload: csrfGuardRequestWithoutToken.payload,
      },
    );

    // Then CSRF guard rejects the request deterministically
    expect(result.status).toBe(403);
    expect(result.body).toMatchObject({
      ok: false,
      code: 'CSRF_TOKEN_REQUIRED',
      refusalType: 'security',
    });
  });

  test.skip('accepts cross-subdomain state-changing fetch when csrf proof pair is valid @P1', async ({
    page,
    csrfGuardRequest,
  }) => {
    // Given browser context includes valid CSRF header and body proof token pair
    await page.goto('/');

    // When app surface performs a state-changing request to the API surface
    const result = await page.evaluate(
      async ({ headers, payload }) => {
        const response = await fetch('/api/v1/platform/_kernel/security/csrf/guard', {
          method: 'POST',
          credentials: 'include',
          headers: {
            'content-type': 'application/json',
            ...headers,
          },
          body: JSON.stringify(payload),
        });

        return {
          status: response.status,
          body: await response.json(),
        };
      },
      {
        headers: csrfGuardRequest.headers,
        payload: csrfGuardRequest.payload,
      },
    );

    // Then request is accepted and mutation proceeds safely
    expect(result.status).toBe(200);
    expect(result.body).toMatchObject({
      ok: true,
      code: 'CSRF_GUARD_PASSED',
    });
  });

  test.skip('sets parent-domain cookie attributes that are shared by app and api hosts @P1', async ({
    context,
    request,
    cookiePolicyProbe,
    parentDomainHosts,
  }) => {
    // Given production cookie policy bootstrap for sibling subdomains
    const bootstrapResponse = await request.post('/api/v1/platform/_kernel/security/cookies/bootstrap', {
      headers: cookiePolicyProbe.headers,
      data: cookiePolicyProbe.payload,
    });

    // Then bootstrap succeeds and emits parent-domain cookies
    expect(bootstrapResponse.status()).toBe(200);

    const cookies = await context.cookies([parentDomainHosts.appOrigin, parentDomainHosts.apiOrigin]);
    const accessCookie = cookies.find((cookie) => cookie.name === 'access_token');
    const refreshCookie = cookies.find((cookie) => cookie.name === 'refresh_token');

    expect(accessCookie).toMatchObject({
      domain: cookiePolicyProbe.expected.parentDomain,
      httpOnly: true,
      secure: cookiePolicyProbe.expected.secure,
      sameSite: 'Strict',
    });
    expect(refreshCookie).toMatchObject({
      domain: cookiePolicyProbe.expected.parentDomain,
      httpOnly: true,
      secure: cookiePolicyProbe.expected.secure,
      sameSite: 'Strict',
    });
  });
});
